def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentence = ""
    main_subjects = []
    for subject, triples in subject_map.items():
        if subject not in main_subjects:
            main_subjects.append(subject)
            if sentence:
                sentence += " which "
            sentence += f"{subject} "
            for i, (predicate, obj) in enumerate(triples):
                if predicate == "cityServed":
                    sentence += f"serves the city of {obj}"
                elif predicate == "location":
                    sentence += f"located in {obj}"
                elif predicate == "elevationAboveTheSeaLevel":
                    sentence += f"at an elevation of {obj} meters above sea level"
                elif predicate == "runwayLength":
                    sentence += f"with a runway length of {obj} meters"
                elif predicate == "country":
                    sentence += f"in {obj}"
                elif predicate == "capital":
                    sentence += f", with {obj} as its capital"
                elif predicate == "isPartOf":
                    sentence += f", part of {obj}"
                elif predicate == "mayor":
                    sentence += f"led by {obj}"
                elif predicate == "operatingOrganisation":
                    sentence += f"operated by {obj}"
                elif predicate == "owner":
                    sentence += f"owned by {obj}"
                elif predicate == "1stRunwayLengthFeet":
                    sentence += f"with a first runway length of {obj} feet"
                elif predicate == "1stRunwaySurfaceType":
                    sentence += f"and a first runway surface type of {obj}"
                elif predicate == "3rdRunwayLengthFeet":
                    sentence += f"and a third runway length of {obj} feet"
                elif predicate == "icaoLocationIdentifier":
                    sentence += f"identified by ICAO as {obj}"
                elif predicate == "locationIdentifier":
                    sentence += f"with location identifier {obj}"
                elif predicate == "elevationAboveTheSeaLevelInFeet":
                    sentence += f"at an elevation of {obj} feet above sea level"
                elif predicate == "iataLocationIdentifier":
                    sentence += f"identified by IATA as {obj}"
                elif predicate == "nativeName":
                    sentence += f"also known as {obj}"
                elif predicate == "leaderParty":
                    sentence += f"with a leader from {obj}"
                elif predicate == "runwayName":
                    sentence += f"with a runway named {obj}"
                elif predicate == "2ndRunwaySurfaceType":
                    sentence += f"and a second runway surface type of {obj}"
                elif predicate == "3rdRunwaySurfaceType":
                    sentence += f"and a third runway surface type of {obj}"
                elif predicate == "4thRunwaySurfaceType":
                    sentence += f"and a fourth runway surface type of {obj}"
                elif predicate == "5thRunwaySurfaceType":
                    sentence += f"and a fifth runway surface type of {obj}"
                elif predicate == "runwaySurfaceType":
                    sentence += f"with a runway surface type of {obj}"
                else:
                    sentence += f", featuring a {predicate} of {obj}"
                if i < len(triples) - 1:
                    sentence += ", "
        if len(subject_map) > 1:
            sentence += ", "
    return sentence + "."

